ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?daily_limit ?transaction_limit WHERE {
  ?limits a :Limits .
  ?accounts a :Accounts .
  ?limits p:hasAccounts ?accounts .
  ?limits p:Daily_Limit ?daily_limit .
  ?limits p:Transaction_Limit ?transaction_limit .
  ?accounts p:Balance ?balance_f .
  FILTER(xsd:double(?balance_f) < 5000)
} }
  component: { SELECT ?daily_limit WHERE {
  ?limits a :Limits .
  ?accounts a :Accounts .
  ?limits p:hasAccounts ?accounts .
  ?limits p:Daily_Limit ?daily_limit .
  ?accounts p:Balance ?balance_f .
  FILTER(xsd:double(?balance_f) < 5000)
} }
  component_2: { SELECT ?transaction_limit WHERE {
  ?limits a :Limits .
  ?accounts a :Accounts .
  ?limits p:hasAccounts ?accounts .
  ?limits p:Transaction_Limit ?transaction_limit .
  ?accounts p:Balance ?balance_f .
  FILTER(xsd:double(?balance_f) < 5000)
} }
}

